from fastapi import FastAPI
from calculator_functions import Calculator
import numbers

app = FastAPI()

# Create a single instance of the calculator
calculator = Calculator()

@app.get("/")
async def root():
    return {"message": "Welcome to the calculator API"}

@app.get("/add/{num1}/{num2}")
async def add(num1: float, num2: float):
    try:
        result = calculator.add(num1, num2)
        return {"result": result}
    except Exception as e:
        return {"error": str(e)}

