import numbers

class Calculator:
    def add(self, num1: float, num2: float) -> float:
        # Add two numbers
        if not isinstance(num1, numbers.Number) or not isinstance(num2, numbers.Number):
            raise TypeError("Both inputs must be numbers")
        return num1 + num2

    def subtract(self, num1: float, num2: float) -> float:
        # Subtract two numbers
        if not isinstance(num1, numbers.Number) or not isinstance(num2, numbers.Number):
            raise TypeError("Both inputs must be numbers")
        return num1 - num2

    def multiply(self, num1: float, num2: float) -> float:
        # Multiply two numbers
        if not isinstance(num1, numbers.Number) or not isinstance(num2, numbers.Number):
            raise TypeError("Both inputs must be numbers")
        return num1 * num2

    def divide(self, num1: float, num2: float) -> float:
        # Divide two numbers
        if not isinstance(num1, numbers.Number) or not isinstance(num2, numbers.Number):
            raise TypeError("Both inputs must be numbers")
        if num2 == 0:
            raise ZeroDivisionError("Cannot divide by zero")
        return num1 / num2

import tkinter as tk
from calculator_functions import Calculator
import re

class CalculatorUI:
    def __init__(self):
        self.window = tk.Tk()
        self.window.title("Calculator")
        self.entry = tk.Entry(self.window)
        self.entry.grid(row=0, column=0, columnspan=4)
        self.create_buttons()
        self.calculator = Calculator()

    def create_buttons(self):
        buttons = [
            '7', '8', '9', '/',
            '4', '5', '6', '*',
            '1', '2', '3', '-',
            '0', '.', '=', '+'
        ]
        row_val = 1
        col_val = 0
        for button in buttons:
            tk.Button(self.window, text=button, width=5, command=lambda button=button: self.click_button(button)).grid(row=row_val, column=col_val)
            col_val += 1
            if col_val > 3:
                col_val = 0
                row_val += 1

    def click_button(self, button):
        try:
            if button == '=':
                result = self.evaluate_expression(self.entry.get())
                self.entry.delete(0, tk.END)
                self.entry.insert(tk.END, str(result))
            else:
                self.entry.insert(tk.END, button)
        except Exception as e:
            self.entry.delete(0, tk.END)
            self.entry.insert(tk.END, str(e))

    def evaluate_expression(self, expression: str):
        # Simple arithmetic parser using regular expressions
        try:
            # Split the expression into numbers and operators
            tokens = re.findall('[+-/*()]|[0-9]+(?:\.[0-9]+)?', expression)
            # Evaluate the expression
            result = self.calculate(tokens)
            return result
        except Exception as e:
            raise e

    def calculate(self, tokens):
        # Recursive descent parser
        if len(tokens) == 1:
            return float(tokens[0])
        elif tokens[1] == '+':
            return float(tokens[0]) + self.calculate(tokens[2:])
        elif tokens[1] == '-':
            return float(tokens[0]) - self.calculate(tokens[2:])
        elif tokens[1] == '*':
            return float(tokens[0]) * self.calculate(tokens[2:])
        elif tokens[1] == '/':
            if float(tokens[2]) == 0:
                raise ZeroDivisionError("Cannot divide by zero")
            return float(tokens[0]) / self.calculate(tokens[2:])

    def run(self):
        self.window.mainloop()

class ErrorHandler:
    def handle_error(self, error: Exception) -> str:
        # Handle error and return error message
        return f"Error type: {type(error).__name__}, Error message: {str(error)}"

import unittest
from calculator_functions import Calculator

class TestCalculator(unittest.TestCase):
    def test_add(self):
        calculator = Calculator()
        self.assertEqual(calculator.add(2, 2), 4)

    def test_subtract(self):
        calculator = Calculator()
        self.assertEqual(calculator.subtract(4, 2), 2)

    def test_multiply(self):
        calculator = Calculator()
        self.assertEqual(calculator.multiply(2, 2), 4)

    def test_divide(self):
        calculator = Calculator()
        self.assertEqual(calculator.divide(4, 2), 2)

    def test_divide_by_zero(self):
        calculator = Calculator()
        with self.assertRaises(ZeroDivisionError):
            calculator.divide(4, 0)
        try:
            calculator.divide(4, 0)
        except ZeroDivisionError as e:
            self.assertEqual(str(e), "Cannot divide by zero")

    def test_divide_by_small_number(self):
        calculator = Calculator()
        self.assertAlmostEqual(calculator.divide(4, 0.0001), 40000)

if __name__ == '__main__':
    unittest.main()
